// ============================================================
// CONFIGURATION — Edit these values for your environment
// ============================================================
const CONFIG = {
  // Helpdesk / ticketing API
  ticketApiUrl: 'https://YOUR_HELPDESK.zendesk.com/api/v2/tickets.json',
  // Knowledge base API
  kbApiUrl: 'https://YOUR_HELPDESK.zendesk.com/api/v2/help_center/articles.json',
  // Slack webhook for notifications
  slackWebhookUrl: 'https://hooks.slack.com/services/YOUR/WEBHOOK/URL',
  // Minimum tickets on a topic before it's flagged as a gap
  gapThreshold: 3,
  // Days after which an article is considered potentially stale
  staleDays: 90,
  // Company/product name for article drafting context
  emailTo: 'user@example.com',
  emailFrom: 'user@example.com',
  emailEnabled: true,
  companyName: 'YourCompany',
  productName: 'YourProduct'
};

return [{ json: CONFIG }];

// Normalize support tickets into a standard format
const tickets = $input.all();
const normalized = [];

for (const item of tickets) {
  const ticket = item.json;
  // Adapt field names to your helpdesk's API response
  normalized.push({
    id: ticket.id || ticket.ticket_id,
    subject: ticket.subject || ticket.title || '',
    description: ticket.description || ticket.body || ticket.content || '',
    tags: ticket.tags || [],
    category: ticket.category || ticket.type || 'general',
    created_at: ticket.created_at || ticket.createdAt,
    resolution: ticket.resolution || ticket.comment || ticket.answer || '',
    customer_satisfaction: ticket.satisfaction_rating?.score || null,
    url: ticket.url || ticket.html_url || ''
  });
}

// Truncate descriptions to save tokens
const truncated = normalized.map(t => ({
  ...t,
  description: t.description.substring(0, 500),
  resolution: t.resolution.substring(0, 500)
}));

return [{ json: { tickets: truncated, ticketCount: truncated.length } }];

// Normalize KB articles into a standard format
const articles = $input.all();
const normalized = [];

for (const item of articles) {
  const article = item.json;
  normalized.push({
    id: article.id || article.article_id,
    title: article.title || article.name || '',
    body: (article.body || article.content || article.description || '').substring(0, 800),
    category: article.section?.name || article.category || article.folder || 'uncategorized',
    tags: article.label_names || article.tags || [],
    last_updated: article.updated_at || article.editedTime || article.lastModified,
    view_count: article.view_count || article.views || 0,
    vote_sum: article.vote_sum || article.helpful_count || 0,
    url: article.html_url || article.url || ''
  });
}

return [{ json: { articles: normalized, articleCount: normalized.length } }];

// Prepare the combined payload for the Gap Analysis Agent
const items = $input.all();
let tickets = [];
let articles = [];
let config = {};

for (const item of items) {
  if (item.json.tickets) tickets = item.json.tickets;
  if (item.json.articles) articles = item.json.articles;
  if (item.json.gapThreshold) config = item.json;
}

// Create a condensed article index for the AI (titles + categories only)
const articleIndex = articles.map(a => ({
  title: a.title,
  category: a.category,
  tags: a.tags,
  last_updated: a.last_updated
}));

// Group tickets by subject similarity (simple keyword extraction)
const topicMap = {};
for (const ticket of tickets) {
  const key = ticket.category + '::' + (ticket.tags?.[0] || 'general');
  if (!topicMap[key]) topicMap[key] = [];
  topicMap[key].push({
    subject: ticket.subject,
    description: ticket.description.substring(0, 200)
  });
}

return [{
  json: {
    ticketCount: tickets.length,
    articleCount: articles.length,
    topicGroups: topicMap,
    articleIndex: articleIndex,
    tickets: tickets,
    articles: articles,
    config: config
  }
}];

// Parse the Gap Analysis Agent output
const output = $input.first().json;
let analysis;

try {
  // The agent may return the JSON in .output or .text
  const raw = output.output || output.text || JSON.stringify(output);
  // Extract JSON from the response (handle potential markdown wrapping)
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  analysis = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  analysis = {
    gaps: [],
    weak_coverage: [],
    stale_articles: [],
    summary: {
      total_gaps_found: 0,
      total_weak_coverage: 0,
      total_stale: 0,
      overall_kb_health_score: 0,
      top_priority_action: 'ERROR: Could not parse gap analysis — check agent output'
    },
    _parse_error: e.message,
    _raw_output: (output.output || output.text || '').substring(0, 500)
  };
}

// Pass through the original data for downstream agents
return [{
  json: {
    analysis: analysis,
    hasGaps: (analysis.gaps?.length || 0) > 0,
    gapCount: analysis.gaps?.length || 0,
    config: $('Prepare Analysis Payload').first().json.config,
    articles: $('Prepare Analysis Payload').first().json.articles
  }
}];

// Split gaps into individual items for the Article Drafter
const data = $input.first().json;
const gaps = data.analysis.gaps || [];
const config = data.config || {};

return gaps.map(gap => ({
  json: {
    gap: gap,
    companyName: config.companyName || 'YourCompany',
    productName: config.productName || 'YourProduct'
  }
}));

// Parse the drafted article from the agent's output
const output = $input.first().json;
let article;

try {
  const raw = output.output || output.text || JSON.stringify(output);
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  article = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  article = {
    title: 'DRAFT PARSE ERROR',
    body_markdown: (output.output || output.text || '').substring(0, 2000),
    _error: e.message
  };
}

return [{ json: { drafted_article: article, status: 'draft' } }];

// Parse the quality review and combine with the article
const output = $input.first().json;
let review;

try {
  const raw = output.output || output.text || JSON.stringify(output);
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  review = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  review = {
    overall_score: 0,
    verdict: 'revise',
    issues: ['Could not parse quality review'],
    _error: e.message
  };
}

// Get the original article from upstream
const articleData = $('Parse Drafted Article').first().json;

return [{
  json: {
    article: articleData.drafted_article,
    review: review,
    verdict: review.verdict,
    score: review.overall_score,
    ready_to_publish: review.verdict === 'publish'
  }
}];

// Staleness check on existing KB articles
const data = $input.first().json;
const articles = data.articles || [];
const staleDays = data.config?.staleDays || 90;
const analysis = data.analysis || {};

const now = new Date();
const staleArticles = [];

for (const article of articles) {
  if (!article.last_updated) continue;
  const updated = new Date(article.last_updated);
  const daysSince = Math.floor((now - updated) / (1000 * 60 * 60 * 24));

  if (daysSince > staleDays) {
    staleArticles.push({
      title: article.title,
      category: article.category,
      last_updated: article.last_updated,
      days_since_update: daysSince,
      view_count: article.view_count,
      vote_sum: article.vote_sum,
      url: article.url,
      priority: daysSince > 180 ? 'high' : daysSince > 120 ? 'medium' : 'low'
    });
  }
}

// Sort by priority (high first) then by days since update
staleArticles.sort((a, b) => {
  const prio = { high: 0, medium: 1, low: 2 };
  return (prio[a.priority] - prio[b.priority]) || (b.days_since_update - a.days_since_update);
});

return [{
  json: {
    staleArticles: staleArticles,
    staleCount: staleArticles.length,
    analysis: analysis
  }
}];

parameters.text:
You are an Executive Report Generator AI agent. Compile a comprehensive Knowledge Base Health Report from the following data.

## GAP ANALYSIS SUMMARY
{{ JSON.stringify($json.analysis?.summary || {}, null, 2) }}

## IDENTIFIED GAPS
{{ JSON.stringify($json.analysis?.gaps || [], null, 2) }}

## WEAK COVERAGE AREAS
{{ JSON.stringify($json.analysis?.weak_coverage || [], null, 2) }}

## STALE ARTICLES ({{ $json.staleCount || 0 }} found)
{{ JSON.stringify(($json.staleArticles || []).slice(0, 20), null, 2) }}

## DRAFTED ARTICLES (if any)
{{ JSON.stringify($json.drafted_articles || [], null, 2) }}

## YOUR TASK

Generate an executive-friendly Knowledge Base Health Report that includes:

1. **Health Score** — Overall KB health (0-100) with a letter grade (A-F)
2. **Executive Summary** — 2-3 sentence overview of KB state
3. **Key Findings** — Bullet points of the most important discoveries
4. **Gaps Requiring Immediate Action** — Priority-ordered list with expected ticket deflection impact
5. **Stale Content Alert** — Articles that need urgent review
6. **Articles Drafted This Cycle** — Summary of auto-drafted articles with quality scores
7. **Recommended Actions** — Prioritized next steps for the knowledge team
8. **Trend Indicator** — Whether KB health is improving, stable, or declining (based on gap count vs article count ratio)

## OUTPUT FORMAT

Respond with valid JSON:
{
  "report_date": "string (ISO date)",
  "health_score": number,
  "health_grade": "A|B|C|D|F",
  "executive_summary": "string",
  "key_findings": ["string"],
  "critical_gaps": [
    {
      "topic": "string",
      "urgency": "string",
      "estimated_ticket_deflection": "string",
      "action_required": "string"
    }
  ],
  "stale_content_alerts": [
    {
      "article": "string",
      "days_stale": number,
      "action": "string"
    }
  ],
  "articles_drafted": [
    {
      "title": "string",
      "quality_score": number,
      "verdict": "string"
    }
  ],
  "recommended_actions": [
    {
      "priority": number,
      "action": "string",
      "expected_impact": "string",
      "effort": "low|medium|high"
    }
  ],
  "trend": "improving|stable|declining",
  "slack_summary": "string (2-3 line summary for Slack notification)"
}

