// Parse the final report and format for Slack + Email
const output = $input.first().json;
let report;

try {
  const raw = output.output || output.text || JSON.stringify(output);
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  report = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  report = {
    executive_summary: 'Report generation encountered an error: ' + e.message,
    health_score: 0,
    health_grade: 'F',
    critical_gaps: [],
    recommended_actions: [],
    stale_articles: [],
    metrics: {}
  };
}

// Determine health emoji
const score = report.health_score || 0;
const grade = report.health_grade || 'N/A';
let healthEmoji = '🔴';
if (score >= 90) healthEmoji = '🟢';
else if (score >= 75) healthEmoji = '🟡';
else if (score >= 60) healthEmoji = '🟠';

const config = $('Configuration').first().json;

// === SLACK PAYLOAD ===
const slackBlocks = {
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: healthEmoji + ' KB Health Report: ' + grade + ' (' + score + '/100)' } },
    { type: 'section', text: { type: 'mrkdwn', text: '*Executive Summary*\n' + (report.executive_summary || 'No summary available') } },
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: '*Key Findings*\n• Critical Gaps: ' + (report.critical_gaps?.length || 0) + '\n• Stale Articles: ' + (report.stale_articles?.length || 0) + '\n• Recommended Actions: ' + (report.recommended_actions?.length || 0) } }
  ]
};

if (report.recommended_actions?.length > 0) {
  slackBlocks.blocks.push({ type: 'divider' });
  slackBlocks.blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Top Actions*\n' + report.recommended_actions.slice(0, 5).map((a, i) => (i+1) + '. ' + (a.action || a.title || a)).join('\n') } });
}

// === EMAIL HTML ===
const scoreColor = score >= 90 ? '#22c55e' : score >= 75 ? '#eab308' : score >= 60 ? '#f97316' : '#ef4444';

let gapsHtml = '';
if (report.critical_gaps?.length > 0) {
  gapsHtml = '<table style="width:100%;border-collapse:collapse;margin:16px 0"><tr style="background:#f1f5f9"><th style="text-align:left;padding:8px;border:1px solid #e2e8f0">Gap</th><th style="text-align:left;padding:8px;border:1px solid #e2e8f0">Urgency</th><th style="text-align:left;padding:8px;border:1px solid #e2e8f0">Impact</th></tr>';
  report.critical_gaps.forEach(g => {
    const urgencyColor = (g.urgency||'').toLowerCase() === 'high' ? '#ef4444' : (g.urgency||'').toLowerCase() === 'medium' ? '#f97316' : '#22c55e';
    gapsHtml += '<tr><td style="padding:8px;border:1px solid #e2e8f0">' + (g.topic || g.title || 'Unknown') + '</td><td style="padding:8px;border:1px solid #e2e8f0"><span style="background:' + urgencyColor + ';color:white;padding:2px 8px;border-radius:12px;font-size:12px">' + (g.urgency || 'N/A') + '</span></td><td style="padding:8px;border:1px solid #e2e8f0">' + (g.impact || g.ticket_volume || 'N/A') + '</td></tr>';
  });
  gapsHtml += '</table>';
}

let actionsHtml = '';
if (report.recommended_actions?.length > 0) {
  actionsHtml = '<table style="width:100%;border-collapse:collapse;margin:16px 0"><tr style="background:#f1f5f9"><th style="text-align:left;padding:8px;border:1px solid #e2e8f0">#</th><th style="text-align:left;padding:8px;border:1px solid #e2e8f0">Action</th><th style="text-align:left;padding:8px;border:1px solid #e2e8f0">Priority</th></tr>';
  report.recommended_actions.forEach((a, i) => {
    actionsHtml += '<tr><td style="padding:8px;border:1px solid #e2e8f0">' + (i+1) + '</td><td style="padding:8px;border:1px solid #e2e8f0">' + (a.action || a.title || a) + '</td><td style="padding:8px;border:1px solid #e2e8f0">' + (a.priority || 'Normal') + '</td></tr>';
  });
  actionsHtml += '</table>';
}

const emailHtml = `<div style="font-family:Arial,sans-serif;max-width:640px;margin:0 auto;padding:24px">
  <div style="text-align:center;margin-bottom:24px">
    <div style="display:inline-block;width:80px;height:80px;line-height:80px;border-radius:50%;background:${scoreColor};color:white;font-size:28px;font-weight:bold">${score}</div>
    <h1 style="margin:12px 0 4px;color:#1e293b">${healthEmoji} KB Health Report</h1>
    <p style="color:#64748b;margin:0">Grade: ${grade} | Generated: ${new Date().toLocaleDateString()}</p>
  </div>
  <div style="background:#f8fafc;border-left:4px solid ${scoreColor};padding:16px;margin:16px 0;border-radius:0 8px 8px 0">
    <h3 style="margin:0 0 8px;color:#1e293b">Executive Summary</h3>
    <p style="margin:0;color:#475569">${report.executive_summary || 'No summary available'}</p>
  </div>
  <div style="display:flex;gap:12px;margin:16px 0">
    <div style="flex:1;background:#fef2f2;padding:12px;border-radius:8px;text-align:center"><strong style="font-size:24px;color:#ef4444">${report.critical_gaps?.length || 0}</strong><br><span style="color:#64748b;font-size:13px">Critical Gaps</span></div>
    <div style="flex:1;background:#fefce8;padding:12px;border-radius:8px;text-align:center"><strong style="font-size:24px;color:#eab308">${report.stale_articles?.length || 0}</strong><br><span style="color:#64748b;font-size:13px">Stale Articles</span></div>
    <div style="flex:1;background:#eff6ff;padding:12px;border-radius:8px;text-align:center"><strong style="font-size:24px;color:#3b82f6">${report.recommended_actions?.length || 0}</strong><br><span style="color:#64748b;font-size:13px">Actions</span></div>
  </div>
  ${gapsHtml ? '<h2 style="color:#1e293b;border-bottom:2px solid #e2e8f0;padding-bottom:8px">Critical Gaps</h2>' + gapsHtml : ''}
  ${actionsHtml ? '<h2 style="color:#1e293b;border-bottom:2px solid #e2e8f0;padding-bottom:8px">Recommended Actions</h2>' + actionsHtml : ''}
  <div style="margin-top:24px;padding:16px;background:#f8fafc;border-radius:8px;text-align:center;color:#94a3b8;font-size:12px">Generated by AI KB Auto-Curator | ${config.companyName || 'YourCompany'}</div>
</div>`;

const emailSubject = healthEmoji + ' KB Health Report: Score ' + score + '/100 (' + grade + ')';

// Return TWO items: one for Slack, one for Email
return [
  { json: { report, slackPayload: slackBlocks, type: 'slack_notification' } },
  { json: { report, emailHtml, emailSubject, type: 'email_report' } }
];

// No gaps found — generate a 'clean' report
const data = $input.first().json;

return [{
  json: {
    analysis: data.analysis || { summary: { total_gaps_found: 0, overall_kb_health_score: 90 } },
    staleArticles: [],
    staleCount: 0,
    drafted_articles: [],
    articles: data.articles || [],
    config: data.config || {},
    noGapsMessage: 'No knowledge gaps detected in this cycle. Your KB is in good shape!'
  }
}];
